  ch_check_ok: { bg:'Връзката работи. Намерени разговори: {0}.', ru:'Связь работает. Найдено диалогов: {0}.', uk:'Зв’язок працює. Знайдено діалогів: {0}.', en:'Connection works. Conversations found: {0}.', de:'Verbindung funktioniert. Gefundene Unterhaltungen: {0}.', fr:'La connexion fonctionne. Conversations trouvées : {0}.', es:'La conexión funciona. Conversaciones encontradas: {0}.', 'es-MX':'La conexión funciona. Conversaciones encontradas: {0}.', it:'La connessione funziona. Conversazioni trovate: {0}.', pt:'A conexão funciona. Conversas encontradas: {0}.', ar:'الاتصال يعمل. المحادثات الموجودة: {0}.', hi:'कनेक्शन काम कर रहा है। मिली बातचीत: {0}।', ja:'接続は正常です。見つかった会話：{0}。', ky:'Туташуу иштейт. Табылган маектер: {0}.', 'zh-Hant':'連線正常。找到對話：{0}。' },
