  perm_notif_denied: { bg:'Известията са отказани (ще ползваме toast).', ru:'Уведомления отклонены (будем использовать toast).', uk:'Сповіщення відхилено (використовуватимемо toast).', en:'Notifications denied (we’ll use a toast).', de:'Benachrichtigungen abgelehnt (wir nutzen einen Toast).', fr:'Notifications refusées (nous utiliserons un toast).', es:'Notificaciones denegadas (usaremos un toast).', 'es-MX':'Notificaciones denegadas (usaremos un toast).', it:'Notifiche negate (useremo un toast).', pt:'Notificações negadas (usaremos um toast).', ar:'تم رفض الإشعارات (سنستخدم toast).', hi:'सूचनाएँ अस्वीकृत (हम toast का उपयोग करेंगे)।', ja:'通知が拒否されました（toastを使用します）。', ky:'Эскертмелер четке кагылды (toast колдонобуз).', 'zh-Hant':'通知遭拒（將改用 toast）。' },
  perm_not_title: { bg:'Какво НЕ искаме и НЕ правим', ru:'Что мы НЕ просим и НЕ делаем', uk:'Що ми НЕ просимо і НЕ робимо', en:'What we do NOT ask for and do NOT do', de:'Was wir NICHT verlangen und NICHT tun', fr:'Ce que nous NE demandons PAS et NE faisons PAS', es:'Lo que NO pedimos y NO hacemos', 'es-MX':'Lo que NO pedimos y NO hacemos', it:'Cosa NON chiediamo e NON facciamo', pt:'O que NÃO pedimos e NÃO fazemos', ar:'ما لا نطلبه ولا نفعله', hi:'हम क्या नहीं माँगते और नहीं करते', ja:'要求しない・しないこと', ky:'Биз эмнени сурабайбыз жана кылбайбыз', 'zh-Hant':'我們不要求也不做的事' },
