  perm_no2: { bg:'🚫 Без акаунти/вход.', ru:'🚫 Без аккаунтов/входа.', uk:'🚫 Без акаунтів/входу.', en:'🚫 No accounts/login.', de:'🚫 Keine Konten/Anmeldung.', fr:'🚫 Aucun compte/connexion.', es:'🚫 Sin cuentas/inicio de sesión.', 'es-MX':'🚫 Sin cuentas/inicio de sesión.', it:'🚫 Nessun account/accesso.', pt:'🚫 Sem contas/login.', ar:'🚫 بلا حسابات/تسجيل دخول.', hi:'🚫 कोई खाते/लॉगिन नहीं।', ja:'🚫 アカウント／ログインなし。', ky:'🚫 Аккаунттар/кирүү жок.', 'zh-Hant':'🚫 無帳戶／登入。' },
  perm_no3: { bg:'🚫 Без локация и без проследяване/анализи.', ru:'🚫 Без локации и без слежки/аналитики.', uk:'🚫 Без локації і без стеження/аналітики.', en:'🚫 No location and no tracking/analytics.', de:'🚫 Kein Standort und kein Tracking/keine Analyse.', fr:'🚫 Aucune localisation ni suivi/analyse.', es:'🚫 Sin ubicación y sin rastreo/analíticas.', 'es-MX':'🚫 Sin ubicación y sin rastreo/analíticas.', it:'🚫 Nessuna posizione e nessun tracciamento/analisi.', pt:'🚫 Sem localização e sem rastreamento/análises.', ar:'🚫 لا موقع ولا تتبّع/تحليلات.', hi:'🚫 कोई लोकेशन और कोई ट्रैकिंग/एनालिटिक्स नहीं।', ja:'🚫 位置情報なし、追跡／解析なし。', ky:'🚫 Жайгашуу жок, аңдуу/аналитика жок.', 'zh-Hant':'🚫 無定位、無追蹤／分析。' },
  perm_no4: { bg:'🚫 Без мрежа за ядрото — правилата работят офлайн.', ru:'🚫 Без сети для ядра — правила работают офлайн.', uk:'🚫 Без мережі для ядра — правила працюють офлайн.', en:'🚫 No network for the core — the rules work offline.', de:'🚫 Kein Netzwerk für den Kern — die Regeln funktionieren offline.', fr:'🚫 Aucun réseau pour le cœur — les règles fonctionnent hors ligne.', es:'🚫 Sin red para el núcleo — las reglas funcionan sin conexión.', 'es-MX':'🚫 Sin red para el núcleo — las reglas funcionan sin conexión.', it:'🚫 Nessuna rete per il core — le regole funzionano offline.', pt:'🚫 Sem rede para o núcleo — as regras funcionam offline.', ar:'🚫 لا شبكة للنواة — تعمل القواعد دون اتصال.', hi:'🚫 कोर के लिए कोई नेटवर्क नहीं — नियम ऑफ़लाइन काम करते हैं।', ja:'🚫 コアにネットワーク不要 — ルールはオフラインで動作。', ky:'🚫 Өзөк үчүн тармак жок — эрежелер оффлайн иштейт.', 'zh-Hant':'🚫 核心無需網路——規則離線運作。' },
  perm_no5: { bg:'ℹ️ Достъпът до известия на други приложения (за WhatsApp/Viber/Messenger) се иска ОТДЕЛНО от екрана „Канали" и изисква native билд.', ru:'ℹ️ Доступ к уведомлениям других приложений (для WhatsApp/Viber/Messenger) запрашивается ОТДЕЛЬНО на экране «Каналы» и требует native-сборки.', uk:'ℹ️ Доступ до сповіщень інших застосунків (для WhatsApp/Viber/Messenger) запитується ОКРЕМО на екрані «Канали» і потребує native-збірки.', en:'ℹ️ Access to other apps’ notifications (for WhatsApp/Viber/Messenger) is requested SEPARATELY on the “Channels” screen and needs a native build.', de:'ℹ️ Der Zugriff auf Benachrichtigungen anderer Apps (für WhatsApp/Viber/Messenger) wird SEPARAT im „Kanäle"-Bildschirm angefragt und erfordert einen Native-Build.', fr:'ℹ️ L’accès aux notifications d’autres apps (pour WhatsApp/Viber/Messenger) se demande SÉPARÉMENT depuis l’écran « Canaux » et nécessite un build natif.', es:'ℹ️ El acceso a las notificaciones de otras apps (para WhatsApp/Viber/Messenger) se solicita POR SEPARADO en la pantalla «Canales» y requiere un build nativo.', 'es-MX':'ℹ️ El acceso a las notificaciones de otras apps (para WhatsApp/Viber/Messenger) se solicita POR SEPARADO en la pantalla «Canales» y requiere un build nativo.', it:'ℹ️ L’accesso alle notifiche di altre app (per WhatsApp/Viber/Messenger) si richiede SEPARATAMENTE nella schermata «Canali» e richiede un build nativo.', pt:'ℹ️ O acesso às notificações de outros apps (para WhatsApp/Viber/Messenger) é solicitado SEPARADAMENTE na tela «Canais» e exige um build nativo.', ar:'ℹ️ يُطلب الوصول إلى إشعارات التطبيقات الأخرى (لواتساب/فايبر/ماسنجر) بشكل منفصل من شاشة «القنوات» ويتطلب بناءً أصليًا.', hi:'ℹ️ अन्य ऐप्स की सूचनाओं तक एक्सेस (WhatsApp/Viber/Messenger के लिए) «चैनल» स्क्रीन से अलग से माँगा जाता है और नेटिव बिल्ड चाहिए।', ja:'ℹ️ 他アプリの通知へのアクセス（WhatsApp/Viber/Messenger用）は「チャンネル」画面で別途要求し、NATIVEビルドが必要です。', ky:'ℹ️ Башка колдонмолордун эскертмелерине мүмкүндүк (WhatsApp/Viber/Messenger үчүн) «Каналдар» экранынан ӨЗҮНЧӨ суралат жана native курулушун талап кылат.', 'zh-Hant':'ℹ️ 存取其他應用程式的通知（用於 WhatsApp/Viber/Messenger）需在「頻道」畫面另外要求，並需原生建置。' },
